const IMAGINATION_SRC  = "/amana-assets/club-imagination.svg";


// ─────────────────────────────────────────────────────────────────────────────
// CHAPTERS
// ─────────────────────────────────────────────────────────────────────────────

const CHAPTERS = [
  { id: "home", label: "Home", icon: "M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z M9 22V12h6v10" },
  { id: "foundation", label: "Our Foundation", icon: "M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" },
  { id: "what-we-do", label: "What We Do", icon: "M12 6v6l4 2M12 2a10 10 0 1 0 0 20A10 10 0 0 0 12 2z" },
  { id: "our-people", label: "Our People", icon: "M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2M9 7a4 4 0 1 0 0-8 4 4 0 0 0 0 8zM23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75" },
  { id: "culture", label: "Cultural Framework", icon: "M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" },
  { id: "operations", label: "Daily Operations", icon: "M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2M9 5a2 2 0 0 0 2 2h2a2 2 0 0 0 2-2M9 5a2 2 0 0 1 2-2h2a2 2 0 0 1 2 2" },
  { id: "policies", label: "Policies", icon: "M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8zM14 2v6h6M16 13H8M16 17H8M10 9H8" },
  { id: "child-safety", label: "Child Safety", icon: "M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" },
];

// ─────────────────────────────────────────────────────────────────────────────
// DESIGN TOKENS
// ─────────────────────────────────────────────────────────────────────────────

const C = {
  teal: "#1A4F5C", tealLight: "#2A6B7C", tealDark: "#0F3340",
  tealPale: "#E1F5EE", gold: "#F5A623", goldPale: "#FEF3DC",
  cream: "#FDFAF5", creamDark: "#F2EDE3", white: "#FFFFFF",
  textPrimary: "#1A1A1A", textSecondary: "#4A5568", textMuted: "#9CA3AF",
  border: "#EDE8DF", borderStrong: "#D4C9B8",
};

// ─────────────────────────────────────────────────────────────────────────────
// PRIMITIVES
// ─────────────────────────────────────────────────────────────────────────────

function Svg({ path, size = 18, stroke = "currentColor", fill = "none", sw = 2 }) {
  return (
    <svg viewBox="0 0 24 24" width={size} height={size} fill={fill} stroke={stroke}
      strokeWidth={sw} strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
      <path d={path} />
    </svg>
  );
}

function P({ children, style }) {
  return <p style={{ fontSize: 13.5, color: C.textSecondary, lineHeight: 1.8, fontFamily: "Georgia, serif", marginBottom: 12, ...style }}>{children}</p>;
}

function H2({ children, icon }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16, paddingBottom: 10, borderBottom: `1px solid ${C.border}` }}>
      {icon && (
        <div style={{ width: 32, height: 32, borderRadius: 8, background: C.goldPale, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <Svg path={icon} size={16} stroke={C.teal} />
        </div>
      )}
      <h2 style={{ fontSize: 20, fontWeight: 700, color: C.textPrimary, fontFamily: "Georgia, serif", margin: 0 }}>{children}</h2>
    </div>
  );
}

function H3({ children }) {
  return <h3 style={{ fontSize: 15, fontWeight: 700, color: C.textPrimary, fontFamily: "Georgia, serif", marginBottom: 8, marginTop: 18 }}>{children}</h3>;
}

function Section({ title, icon, children }) {
  return <div style={{ marginBottom: 36 }}>{title && <H2 icon={icon}>{title}</H2>}{children}</div>;
}

function Callout({ children, color = "gold" }) {
  return (
    <div style={{
      background: color === "red" ? "#FCEBEB" : C.creamDark,
      borderLeft: `3px solid ${color === "red" ? "#E24B4A" : C.gold}`,
      borderRadius: "0 8px 8px 0", padding: "12px 14px", margin: "12px 0",
      fontSize: 13, color: C.textSecondary, lineHeight: 1.75, fontFamily: "Georgia, serif",
    }}>{children}</div>
  );
}

function Ul({ items }) {
  return (
    <ul style={{ paddingLeft: 20, margin: "8px 0" }}>
      {items.map((item, i) => (
        <li key={i} style={{ fontSize: 13, color: C.textSecondary, lineHeight: 1.8, marginBottom: 3, fontFamily: "Georgia, serif" }}>
          {Array.isArray(item) ? (<><strong style={{ color: C.textPrimary }}>{item[0]}</strong>{item[1]}</>) : item}
        </li>
      ))}
    </ul>
  );
}

function Grid({ cols = 2, children, gap = 12 }) {
  return <div style={{ display: "grid", gridTemplateColumns: `repeat(${cols}, minmax(0, 1fr))`, gap }}>{children}</div>;
}

function Card({ children, style }) {
  return <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: 10, padding: "14px 16px", ...style }}>{children}</div>;
}

function Divider() {
  return <div style={{ borderTop: `1px solid ${C.border}`, margin: "24px 0" }} />;
}

function ScriptRow({ label, text, editKey }) {
  const labelNode = editKey ? <E k={`${editKey}.label`}>{label}</E> : label;
  const textNode  = editKey ? <E k={`${editKey}.text`}>{text}</E>   : text;
  return (
    <div style={{ borderBottom: `1px solid ${C.border}`, paddingBottom: 10, marginBottom: 10 }}>
      <div style={{ fontSize: 10, color: C.textMuted, letterSpacing: "0.07em", textTransform: "uppercase", fontFamily: "Georgia, serif", marginBottom: 4 }}>{labelNode}</div>
      <div style={{ fontSize: 13.5, color: C.teal, fontStyle: "italic", fontFamily: "Georgia, serif", lineHeight: 1.65 }}>&ldquo;{textNode}&rdquo;</div>
    </div>
  );
}

function ValueCard({ initial, value, desc }) {
  return (
    <Card style={{ display: "flex", gap: 14, alignItems: "flex-start" }}>
      <div style={{ width: 40, height: 40, borderRadius: 8, background: C.teal, color: C.gold, fontFamily: "Georgia, serif", fontSize: 22, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>{initial}</div>
      <div>
        <div style={{ fontSize: 15, fontWeight: 700, color: C.textPrimary, fontFamily: "Georgia, serif", marginBottom: 4 }}>{value}</div>
        <div style={{ fontSize: 13, color: C.textSecondary, fontFamily: "Georgia, serif", lineHeight: 1.7 }}>{desc}</div>
      </div>
    </Card>
  );
}

function RatioTable() {
  const rows = [["Standard service","1:15"],["Low-risk excursion","1:11"],["High-risk excursion","1:8"],["Water-based excursion","1:5"],["Specialist schools","1:2"]];
  return (
    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13, fontFamily: "Georgia, serif", borderRadius: 8, overflow: "hidden", marginBottom: 12 }}>
      <thead><tr style={{ background: C.teal }}><th style={{ padding: "8px 12px", textAlign: "left", color: C.white }}>Setting</th><th style={{ padding: "8px 12px", textAlign: "left", color: C.gold }}>Staff : Children</th></tr></thead>
      <tbody>{rows.map(([s, r], i) => (<tr key={i} style={{ background: i % 2 === 0 ? C.white : C.cream }}><td style={{ padding: "8px 12px", color: C.textSecondary }}>{s}</td><td style={{ padding: "8px 12px", color: C.teal, fontWeight: 700 }}>{r}</td></tr>))}</tbody>
    </table>
  );
}

function AbuseBlock({ title, behavioural, physical }) {
  return (
    <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden", marginBottom: 14 }}>
      <div style={{ background: C.teal, padding: "10px 14px" }}>
        <span style={{ fontSize: 14, fontWeight: 700, color: C.white, fontFamily: "Georgia, serif" }}>{title}</span>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr" }}>
        <div style={{ padding: "12px 14px", borderRight: `1px solid ${C.border}` }}>
          <div style={{ fontSize: 10, color: C.teal, letterSpacing: "0.07em", textTransform: "uppercase", fontFamily: "Georgia, serif", marginBottom: 8 }}>Behavioural indicators</div>
          <ul style={{ paddingLeft: 16, margin: 0 }}>{behavioural.map((x, i) => <li key={i} style={{ fontSize: 12, color: C.textSecondary, lineHeight: 1.7, marginBottom: 2 }}>{x}</li>)}</ul>
        </div>
        <div style={{ padding: "12px 14px" }}>
          <div style={{ fontSize: 10, color: C.teal, letterSpacing: "0.07em", textTransform: "uppercase", fontFamily: "Georgia, serif", marginBottom: 8 }}>Physical indicators</div>
          <ul style={{ paddingLeft: 16, margin: 0 }}>{physical.map((x, i) => <li key={i} style={{ fontSize: 12, color: C.textSecondary, lineHeight: 1.7, marginBottom: 2 }}>{x}</li>)}</ul>
        </div>
      </div>
    </div>
  );
}

